import React from 'react';
import { EventServices, AttendeeServices } from '@/api';
import { EventCard } from '@/pages/events/EventCard';
import { EventResult } from '@/types/event.types';
import { RegisteredEventInfo } from '@/types/attendee.types';
import { CallStatus } from '@/types/api.types';
import { PageContainer } from '@/components/PageContainer';
import { StatusMessage } from '@/components/StatusMessage';
import { Pathname } from '@/constants/Routes';
import { useNavigate } from '@tanstack/react-router';
import { GetUserId } from '@/utils/token';

interface EventViewPageProps {
    eventId?: string;
}

const EventViewPage: React.FC<EventViewPageProps> = ({ eventId: propEventId }) => {
    const navigate = useNavigate();
    const [event, setEvent] = React.useState<EventResult | null>(null);
    const [loading, setLoading] = React.useState<boolean>(true);
    const [error, setError] = React.useState<string | null>(null);
    const [registrationInfo, setRegistrationInfo] = React.useState<RegisteredEventInfo | null>(null);

    React.useEffect(() => {
        const eventId = propEventId;
        if (!eventId) {
            navigate({ to: Pathname.Events as string });
            return;
        }
        const userId = GetUserId();

        Promise.all([
            EventServices.GetEventById(eventId),
            userId ? AttendeeServices.GetAttendeeById(eventId, userId).catch(() => null) : Promise.resolve(null)
        ]).then(([eventResponse, attendeeResponse]) => {
            if (eventResponse.data.status >= 200 && eventResponse.data.status < 300) {
                setEvent(eventResponse.data.result);
            } else {
                setError(`Event "${eventId}" not found.`);
            }
            if (attendeeResponse?.data?.result) {
                const a = attendeeResponse.data.result;
                setRegistrationInfo({
                    eventId: a.eventId,
                    foodPreference: a.foodPreference,
                    headCount: a.headCount,
                    donation: a.donation,
                    registeredAt: a.createdAt,
                });
            }
        }).catch(() => {
            setError(`Failed to load event "${eventId}".`);
        }).finally(() => {
            setLoading(false);
        });
    }, [propEventId, navigate]);

    const handleEventEdit = (eventId: string) => {
        navigate({ to: `${Pathname.Events_Edit}/${eventId}` as string });
    };

    const handleRegistrationChange = () => {
        if (!event) return;
        const userId = GetUserId();
        if (!userId) return;
        AttendeeServices.GetAttendeeById(event.id.toString(), userId)
            .then(response => {
                if (response?.data?.result) {
                    const a = response.data.result;
                    setRegistrationInfo({
                        eventId: a.eventId,
                        foodPreference: a.foodPreference,
                        headCount: a.headCount,
                        donation: a.donation,
                        registeredAt: a.createdAt,
                    });
                } else {
                    setRegistrationInfo(null);
                }
            })
            .catch(() => setRegistrationInfo(null));
    };

    if (loading) {
        return (
            <PageContainer>
                <StatusMessage currentStatus={CallStatus.InProgress} notStartedMessage="" correlationId="" />
            </PageContainer>
        );
    }

    if (!event) {
        return (
            <PageContainer>
                <p>{error || 'Event not found.'}</p>
            </PageContainer>
        );
    }

    return (
        <EventCard
            event={event}
            registrationInfo={registrationInfo}
            onRegistrationChange={handleRegistrationChange}
            onEventEdit={handleEventEdit}
        />
    );
};

export default EventViewPage;
